-- Schema for Domain: engineering | Business:  | Version: v1_mvm
-- Generated on: 2026-04-16 09:51:29

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `manufacturing_ecm`.`engineering` COMMENT 'Owns the complete product engineering lifecycle including CAD/CAM models, BOM (Bill of Materials), BoP (Bill of Process), PLM/PDM records, ECN/ECO change management, DFM/DFA analysis, DFMEA/PFMEA documentation, and prototype development. SSOT for product structure, technical specifications, drawings, and engineering change workflows for automation systems and electrification solutions.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`bom_line` (
    `bom_line_id` BIGINT COMMENT 'Unique surrogate identifier for each individual BOM line item record in the silver layer lakehouse. Serves as the primary key for the bom_line data product.',
    `cad_model_id` BIGINT COMMENT 'Foreign key linking to engineering.cad_model. Business justification: Each BOM line item (component) corresponds to a CAD model in the PLM/PDM system. Linking bom_line to cad_model provides direct traceability from the product structure to the 3D geometry definition, en',
    `ecn_id` BIGINT COMMENT 'Reference to the Engineering Change Notice (ECN) or Engineering Change Order (ECO) that authorized the creation or modification of this BOM line item. Supports full change traceability and audit compliance.',
    `engineering_bom_id` BIGINT COMMENT 'Reference to the parent BOM header to which this line item belongs. Enables multi-level BOM explosion and parent-child component hierarchy traversal for MRP and production planning.',
    `material_specification_id` BIGINT COMMENT 'Foreign key linking to engineering.material_specification. Business justification: BOM line items for raw material or semi-finished components must reference the applicable material specification defining chemical composition, mechanical properties, and compliance requirements. This',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: Every BOM line specifies a component quantity in a unit of measure (each, kg, meter). Referencing the shared UOM table ensures consistency across engineering, procurement, and production quantity calc',
    `alternative_item_group` STRING COMMENT 'Groups multiple BOM line items that are interchangeable alternatives for the same functional requirement. During MRP and production order creation, the system selects the preferred or available alternative based on priority and stock availability. Supports substitute component management and supply chain flexibility.. Valid values are `^[A-Z0-9]{1,2}$`',
    `alternative_item_priority` STRING COMMENT 'Numeric priority rank within an alternative item group, where lower numbers indicate higher preference (1 = first choice). Used by MRP and production planning to determine which substitute component to consume first when multiple alternatives are defined for the same functional position.. Valid values are `^[1-9][0-9]?$`',
    `alternative_item_usage_probability` DECIMAL(18,2) COMMENT 'The probability percentage (0–100) that this alternative component will be selected over other alternatives in the same group during production planning. Used by MRP to distribute planned requirements across alternative components proportionally, supporting multi-source procurement strategies.. Valid values are `^(100(.0{1,2})?|[0-9]{1,2}(.[0-9]{1,2})?)$`',
    `bom_item_number` STRING COMMENT 'Sequential item number assigned to this BOM line within the parent BOM header, typically in increments of 10 (e.g., 0010, 0020). Used for ordering and referencing line items within the BOM structure in SAP PP.. Valid values are `^[0-9]{4,6}$`',
    `bom_level` STRING COMMENT 'The hierarchical depth level of this component within the multi-level BOM structure, where level 0 is the finished good, level 1 is the first-tier sub-assembly, and so on. Used for BOM explosion reporting, MRP low-level code assignment, and production scheduling sequencing.. Valid values are `^[0-9]{1,3}$`',
    `bom_usage` STRING COMMENT 'Defines the business purpose for which this BOM is used, corresponding to SAP BOM usage keys (e.g., 1=Production, 2=Engineering/Design, 3=Universal, 4=Plant Maintenance, 5=Sales, 6=Costing). Determines which BOM is selected during MRP, costing, sales order processing, and maintenance planning.. Valid values are `production|engineering|universal|plant_maintenance|sales|costing|spare_parts`',
    `component_number` STRING COMMENT 'The manufacturer or internal part number of the child component as defined in the material master or PLM system. Used for procurement, inventory lookup, and cross-referencing with supplier catalogs and engineering drawings.. Valid values are `^[A-Z0-9-.]{1,40}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this BOM line record was originally created in the source system. Used for audit trail, change history analysis, and data lineage tracking in compliance with ISO 9001 document control requirements.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `effectivity_end_date` DATE COMMENT 'The date after which this BOM line item is no longer valid for production planning and MRP explosion. Used to phase out obsolete components following an Engineering Change Notice (ECN) while maintaining historical BOM traceability for previously manufactured products.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effectivity_start_date` DATE COMMENT 'The date from which this BOM line item becomes valid and active for use in production planning and MRP explosion. Supports date-effective BOM management for engineering change implementation, ensuring new component versions are introduced at the correct production date.. Valid values are `^d{4}-d{2}-d{2}$`',
    `find_number` STRING COMMENT 'Balloon or find number referencing the components callout position on the engineering drawing or assembly diagram. Used by manufacturing engineers and quality inspectors to locate the component on the drawing during First Article Inspection (FAI) and assembly.. Valid values are `^[A-Z0-9]{1,10}$`',
    `fixed_quantity_indicator` BOOLEAN COMMENT 'Indicates whether the component quantity on this BOM line is fixed regardless of the production order quantity (true) or variable and proportional to the order quantity (false). Fixed quantities are used for setup materials, tooling, or components consumed once per batch regardless of batch size.. Valid values are `true|false`',
    `is_bulk_material` BOOLEAN COMMENT 'Indicates whether this BOM line item is a bulk material (e.g., adhesives, lubricants, solder paste, wire) that is consumed in variable quantities and typically not individually issued to production orders. Bulk materials are often backflushed or managed via replenishment rather than discrete picking.. Valid values are `true|false`',
    `is_co_product` BOOLEAN COMMENT 'Indicates whether this BOM line item is a co-product or by-product produced alongside the primary output of the manufacturing process. Co-products have positive quantity and receive cost allocation; by-products may have negative cost impact. Relevant for process manufacturing and chemical/electrification solution production.. Valid values are `true|false`',
    `is_phantom_assembly` BOOLEAN COMMENT 'Indicates whether this BOM line represents a phantom assembly — a logical grouping of components that is not physically stocked or produced as a discrete item but is exploded through during MRP to directly consume its child components. Common in modular product structures and configurable BOMs.. Valid values are `true|false`',
    `issue_location` STRING COMMENT 'The warehouse storage location from which this component is issued to the production order or work order. Drives automatic goods issue (backflush) and pick list generation in SAP WM/WMS and Infor WMS for shop floor material replenishment.',
    `item_category` STRING COMMENT 'Classification of the BOM line item type as defined in SAP PP. Stock items (L) are warehouse-managed materials; non-stock items (N) are procured directly to the order; document items (D) reference engineering documents; phantom assemblies (P) are logical groupings not physically stocked; variable-size items (R) have variable dimensions.. Valid values are `stock|non_stock|document|variable_size|class|text|intra_material|phantom`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this BOM line record in the source system. Supports incremental data loading, change detection, and audit trail requirements for engineering change management and quality management system (QMS) compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `long_text` STRING COMMENT 'Extended descriptive text or engineering notes associated with this BOM line item. May include assembly instructions, special handling requirements, quality inspection notes, or engineering change justifications visible to production planners and shop floor operators.',
    `operation_activity_number` STRING COMMENT 'The routing operation or activity number to which this BOM component is assigned for consumption. Links the component to the specific manufacturing step in the Bill of Process (BoP) where it is consumed, enabling accurate work-in-progress (WIP) tracking and operation-level material staging.. Valid values are `^[0-9]{4}$`',
    `operation_lead_time_offset` DECIMAL(18,2) COMMENT 'The number of days (positive or negative) by which the component requirement date is offset from the production order start date. Used in multi-level scheduling to stage component availability at the correct operation step, supporting JIT (Just-In-Time) material staging on the shop floor.',
    `plant_code` STRING COMMENT 'The SAP plant code identifying the manufacturing facility or production site for which this BOM line is valid. BOMs can be plant-specific to accommodate local sourcing, manufacturing processes, or regional regulatory requirements across the multinational enterprise.. Valid values are `^[A-Z0-9]{4}$`',
    `procurement_type` STRING COMMENT 'Indicates whether the component on this BOM line is manufactured in-house (make), externally procured (buy), or can be sourced either way. Drives MRP planning logic to generate either planned production orders or purchase requisitions for the component.. Valid values are `in_house|external|both`',
    `quantity` DECIMAL(18,2) COMMENT 'The quantity of the child component required to produce one unit of the parent assembly as specified on this BOM line. Used directly by MRP (Material Requirements Planning) to calculate gross requirements and by production planning for work order component staging.. Valid values are `^[0-9]+(.[0-9]{1,6})?$`',
    `reference_designator` STRING COMMENT 'Alphanumeric label identifying the specific physical location(s) of a component on a printed circuit board (PCB) or assembly drawing (e.g., R1, C12, U5). Critical for electronics manufacturing, PCB assembly, and automated optical inspection (AOI) processes.',
    `scrap_factor_percent` DECIMAL(18,2) COMMENT 'The anticipated scrap or yield loss percentage for this component during the manufacturing process, expressed as a percentage (e.g., 5.00 = 5%). MRP inflates the gross requirement by this factor to account for expected material loss, ensuring sufficient components are procured or issued to production orders.. Valid values are `^(100(.0{1,4})?|[0-9]{1,2}(.[0-9]{1,4})?)$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this BOM line record was sourced (e.g., SAP PP for production BOMs, Siemens Teamcenter for engineering/design BOMs). Supports data lineage tracking and reconciliation between PLM and ERP BOM structures in the silver layer.. Valid values are `SAP_PP|TEAMCENTER|OPCENTER|MANUAL`',
    `source_system_key` STRING COMMENT 'The natural or composite key of this BOM line record as it exists in the originating source system (e.g., SAP BOM number + item number + plant, or Teamcenter BOM line UID). Enables traceability back to the system of record and supports delta load reconciliation in the lakehouse ingestion pipeline.',
    `special_procurement_type` STRING COMMENT 'Specifies a special procurement strategy for this component, such as subcontracting (component sent to external vendor for processing), consignment stock, inter-plant stock transfer, or direct production. Overrides the standard procurement type for specific supply chain scenarios.. Valid values are `consignment|subcontracting|stock_transfer|direct_production|phantom`',
    `status` STRING COMMENT 'Current lifecycle status of this BOM line item. Active lines are included in MRP explosion and production planning. Pending approval lines are awaiting ECN authorization. Obsolete lines are retained for historical traceability but excluded from planning runs.. Valid values are `active|inactive|pending_approval|obsolete|superseded|in_review`',
    `supply_area` STRING COMMENT 'The production supply area or supermarket location on the shop floor where this component is staged for consumption at the work center. Supports Kanban and JIT (Just-In-Time) material flow management in Siemens Opcenter MES and SAP PP.',
    CONSTRAINT pk_bom_line PRIMARY KEY(`bom_line_id`)
) COMMENT 'Individual line-item within a Bill of Materials defining each child component, quantity, unit of measure, reference designator, find number, item category (stock, non-stock, document), scrap factor, and effectivity date range. Supports multi-level BOM explosion for MRP and production planning. Sourced from Siemens Teamcenter BOM line items and SAP PP BOM item records.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`bop_operation` (
    `bop_operation_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying an individual operation step within a Bill of Process. Serves as the primary key for this entity in the Databricks Silver Layer.',
    `bop_id` BIGINT COMMENT 'Foreign key linking to engineering.bop. Business justification: bop_operation is a child record of bop — each operation step belongs to a Bill of Process header. Without this FK, bop_operation is siloed from its parent. This is the fundamental parent-child relatio',
    `pfmea_id` BIGINT COMMENT 'Foreign key linking to engineering.pfmea. Business justification: bop_operation.pfmea_reference_number is a STRING reference to the PFMEA that analyzes failure modes for this operation. Replacing with FK pfmea_id → pfmea.pfmea_id enforces the PFMEA-to-operation trac',
    `tooling_equipment_id` BIGINT COMMENT 'Foreign key linking to engineering.tooling_equipment. Business justification: BOP operations specify required tooling and equipment. Production scheduling and maintenance systems use this to ensure correct tools are available, calibrated, and assigned to workstations before ope',
    `base_quantity` DECIMAL(18,2) COMMENT 'Reference quantity to which the standard time values (machine time, labor time) apply. For example, a machine time of 5 minutes per base quantity of 100 pieces. Corresponds to SAP PP BMSCH field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `base_quantity_unit` STRING COMMENT 'Unit of measure for the base quantity (e.g., EA for each, PC for pieces, KG for kilograms). Aligns with SAP unit of measure configuration and ISO 80000 measurement standards.. Valid values are `EA|PC|KG|M|M2|M3|L|HR|MIN|SET`',
    `control_key` STRING COMMENT 'SAP PP control key (e.g., PP01, PP03, QM01) that governs the scheduling, costing, confirmation, and quality inspection behavior of the operation. Determines whether the operation is relevant for capacity planning, external processing, or quality inspection.',
    `cost_center_code` STRING COMMENT 'SAP cost center code associated with the work center performing this operation. Used for cost allocation, COGS (Cost of Goods Sold) calculation, and financial reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this BoP operation record was first created in the source system. Used for audit trail, data lineage, and change history tracking.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the external processing price (e.g., USD, EUR, CNY). Supports multi-currency operations in multinational manufacturing environments.. Valid values are `^[A-Z]{3}$`',
    `ecn_reference_number` STRING COMMENT 'Reference number of the Engineering Change Notice (ECN) or Engineering Change Order (ECO) that introduced or last modified this operation. Provides full traceability of process changes to engineering change management records.',
    `effective_from_date` DATE COMMENT 'Date from which this operation version becomes valid and can be used in production planning and execution. Supports date-effective routing management and Engineering Change Notice (ECN) implementation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effective_to_date` DATE COMMENT 'Date after which this operation version is no longer valid. Used to manage operation version supersession during Engineering Change Order (ECO) implementation and routing revision cycles.. Valid values are `^d{4}-d{2}-d{2}$`',
    `external_processing_price` DECIMAL(18,2) COMMENT 'Standard price per unit for externally processed operations performed by a subcontractor. Used in product costing and purchase order creation for subcontracting. Corresponds to SAP PP PEINH/PREIS fields.. Valid values are `^[0-9]+(.[0-9]{1,4})?$`',
    `hazardous_material_relevant` BOOLEAN COMMENT 'Flag indicating whether this operation involves handling of hazardous materials, chemicals, or substances subject to REACH, RoHS, or OSHA regulations. Triggers mandatory safety documentation and PPE requirements on the shop floor.. Valid values are `true|false`',
    `inspection_characteristic_group` STRING COMMENT 'Code or identifier of the inspection characteristic group (master inspection characteristic catalog) assigned to this operation for in-process quality control. Defines the measurement parameters and tolerances to be checked.',
    `inspection_relevant` BOOLEAN COMMENT 'Flag indicating whether this operation requires a quality inspection step (in-process inspection). When true, inspection characteristics and AQL (Acceptable Quality Level) parameters must be defined for this operation.. Valid values are `true|false`',
    `interoperation_time_min` DECIMAL(18,2) COMMENT 'Standard wait and move time in minutes between this operation and the next operation in the routing. Includes queue time, move time, and wait time. Used in lead time calculation and scheduling. Corresponds to SAP PP interoperation times.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `labor_time_min` DECIMAL(18,2) COMMENT 'Standard labor time in minutes per base quantity unit required for this operation. Used for workforce planning, labor cost calculation, and takt time analysis. Corresponds to SAP PP ARBZE field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this BoP operation record in the source system. Supports incremental data loading, change detection, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `long_text` STRING COMMENT 'Detailed narrative description of the operation including step-by-step instructions, safety notes, and quality requirements. Supports shop floor instruction generation and Standard Operating Procedure (SOP) documentation.',
    `machine_time_min` DECIMAL(18,2) COMMENT 'Standard machine processing time in minutes per base quantity unit for this operation. Used for capacity planning, OEE (Overall Equipment Effectiveness) calculation, and production scheduling. Corresponds to SAP PP BEAZE field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `maximum_lot_size` DECIMAL(18,2) COMMENT 'Maximum production quantity that can be processed in a single run of this operation. Constrains batch sizes for capacity and quality management purposes.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `minimum_lot_size` DECIMAL(18,2) COMMENT 'Minimum production quantity that can be processed in a single run of this operation. Used in production planning and scheduling to enforce batch size constraints.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `nc_program_number` STRING COMMENT 'Identifier of the CNC (Computer Numerical Control) or NC program used to execute this operation on automated machinery. Links to the CAM (Computer-Aided Manufacturing) system for program retrieval.',
    `number_of_resources` STRING COMMENT 'Number of parallel machines or labor resources required to execute this operation simultaneously. Used for capacity planning and scheduling. Corresponds to SAP PP ANZZL field.. Valid values are `^[1-9][0-9]*$`',
    `operation_description` STRING COMMENT 'Short descriptive text for the operation step, summarizing the manufacturing activity performed (e.g., Weld Frame Assembly, CNC Milling – Housing, Final Inspection). Corresponds to SAP PP LTXA1 field.',
    `operation_number` STRING COMMENT 'Sequential numeric identifier for the operation step within the routing or Bill of Process, typically in increments of 10 (e.g., 0010, 0020, 0030). Corresponds to the SAP PP routing operation number (VORNR) and Teamcenter process step sequence number.. Valid values are `^[0-9]{4}$`',
    `operation_type` STRING COMMENT 'Classification of the operation indicating whether it is performed in-house, by an external subcontractor, or as a quality inspection step. Drives procurement and costing logic.. Valid values are `in_house|external|subcontracting|inspection|rework`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where this operation is performed. Supports multi-plant BoP management for multinational operations.',
    `scheduling_type` STRING COMMENT 'Determines the scheduling direction for this operation in production planning — forward scheduling (from start date), backward scheduling (from required finish date), or current date. Corresponds to SAP PP scheduling parameters.. Valid values are `forward|backward|current_date`',
    `setup_time_min` DECIMAL(18,2) COMMENT 'Standard setup time in minutes required to prepare the work center for this operation, including tooling changeover and machine configuration. Used in capacity planning, scheduling, and SMED (Single-Minute Exchange of Dies) analysis. Corresponds to SAP PP RUSTE field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `sop_reference_number` STRING COMMENT 'Document number or identifier of the Standard Operating Procedure (SOP) governing the execution of this operation. Links to the document management system for shop floor instruction retrieval.',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this BoP operation was sourced (e.g., SAP_PP for SAP S/4HANA PP routing, TEAMCENTER for Siemens Teamcenter manufacturing process steps). Supports data lineage and reconciliation.. Valid values are `SAP_PP|TEAMCENTER|OPCENTER|MANUAL`',
    `standard_cost_activity_type` STRING COMMENT 'SAP CO activity type code used to assign standard costs to this operation (e.g., machine hours, labor hours). Links the operation to cost center accounting and product costing. Corresponds to SAP CO LSTAR field.',
    `status` STRING COMMENT 'Current lifecycle status of the BoP operation record. Active operations are available for production order assignment; obsolete operations are retained for historical traceability but cannot be used in new routings.. Valid values are `active|inactive|draft|under_review|obsolete`',
    `subcontracting_vendor_code` STRING COMMENT 'Vendor or supplier code for externally processed operations where the operation is performed by a subcontractor. Applicable when operation_type is external or subcontracting. Corresponds to SAP PP external processing vendor.',
    `teardown_time_min` DECIMAL(18,2) COMMENT 'Standard teardown or post-processing time in minutes required after the operation is completed, including cleaning, tool removal, and work center reset. Corresponds to SAP PP ABRUE field.. Valid values are `^[0-9]+(.[0-9]{1,3})?$`',
    `tooling_list_reference` STRING COMMENT 'Reference identifier for the tooling list or production resource/tool (PRT) assignment associated with this operation. Specifies jigs, fixtures, cutting tools, and gauges required. Corresponds to SAP PP PRT assignment.',
    `version_number` STRING COMMENT 'Version identifier for this operation step, incremented when the operation is revised through the engineering change process. Enables version-controlled routing management and historical comparison.. Valid values are `^[A-Z0-9.]+$`',
    `work_center_code` STRING COMMENT 'Alphanumeric code identifying the work center (machine, production line, or labor group) where this operation is performed. Corresponds to SAP PP ARBPL field and links to the work center master data.',
    `work_center_name` STRING COMMENT 'Human-readable name of the work center where the operation is executed (e.g., CNC Cell 3, Welding Station A, Final Assembly Line 2). Supports shop floor reporting and scheduling.',
    CONSTRAINT pk_bop_operation PRIMARY KEY(`bop_operation_id`)
) COMMENT 'Individual operation step within a Bill of Process defining the work center, operation description, standard values (setup time, machine time, labor time), control key, inspection characteristics, tooling requirements, and SOP reference. Supports PFMEA linkage and shop floor instruction generation. Sourced from SAP PP routing operations and Teamcenter manufacturing process steps.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`cad_model` (
    `cad_model_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a CAD/CAM design model record within the PLM/PDM system. Serves as the primary key for the cad_model data product in the Databricks Silver layer.',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: cad_model.ecn_number is a STRING reference to the ECN that authorized the CAD model revision. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for design geometry. ecn_num',
    `plm_lifecycle_state_id` BIGINT COMMENT 'Foreign key linking to engineering.plm_lifecycle_state. Business justification: cad_model.lifecycle_state is a STRING that should reference the authoritative PLM lifecycle state reference table. Replacing with FK plm_lifecycle_state_id → plm_lifecycle_state.plm_lifecycle_state_id',
    `bounding_box_x_mm` DECIMAL(18,2) COMMENT 'Maximum extent of the CAD model geometry along the X-axis in millimeters, representing the width of the components bounding envelope. Used for packaging analysis, fixture design, and logistics planning (e.g., pallet/container sizing).',
    `bounding_box_y_mm` DECIMAL(18,2) COMMENT 'Maximum extent of the CAD model geometry along the Y-axis in millimeters, representing the depth of the components bounding envelope. Used for packaging analysis, fixture design, and logistics planning.',
    `bounding_box_z_mm` DECIMAL(18,2) COMMENT 'Maximum extent of the CAD model geometry along the Z-axis in millimeters, representing the height of the components bounding envelope. Used for packaging analysis, fixture design, and logistics planning.',
    `cad_tool` STRING COMMENT 'Name of the CAD/CAM software application used to create and maintain the model (e.g., Siemens NX, CATIA V5/V6, SolidWorks). Determines file format compatibility, interoperability requirements, and licensing needs for downstream engineering and manufacturing processes.. Valid values are `NX|CATIA|SolidWorks|Creo|AutoCAD|Inventor|ANSYS|Simcenter|Fusion360|Other`',
    `cad_tool_version` STRING COMMENT 'Version or release number of the CAD/CAM software used to create or last modify the model (e.g., NX 2206, CATIA V5 R31). Critical for file compatibility management, migration planning, and ensuring models can be opened by the correct software version in the engineering environment.',
    `checked_out_by` STRING COMMENT 'Username or employee ID of the engineer who currently has the CAD model checked out for editing in the PLM/PDM system. A checked-out model is locked for exclusive editing. Null if the model is not currently checked out. Corresponds to Teamcenter Checked Out By.',
    `checkout_timestamp` TIMESTAMP COMMENT 'Date and time when the CAD model was checked out from the PLM/PDM vault for editing. Used to track concurrent engineering activities, identify long-running checkouts that may block other engineers, and support audit trails.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `classification_code` STRING COMMENT 'Standardized classification code assigned to the CAD model based on the companys engineering parts classification system (e.g., eCl@ss, UNSPSC, or internal taxonomy). Enables design reuse, variant management, and supplier sourcing by grouping similar components.',
    `component_type` STRING COMMENT 'Classification of the engineering component or assembly represented by the CAD model. Determines BOM structure, procurement strategy (make vs. buy), and applicable design standards. assembly models link to child part models via the BOM hierarchy in PLM.. Valid values are `part|assembly|sub_assembly|standard_part|purchased_part|raw_material|tooling|fixture|packaging`',
    `coordinate_system` STRING COMMENT 'Type of coordinate system used to define the geometry of the CAD model (e.g., Cartesian, Cylindrical). Ensures correct spatial orientation when integrating models into assemblies, simulation environments, or digital twin platforms.. Valid values are `cartesian|cylindrical|spherical`',
    `country_of_origin` STRING COMMENT 'Three-letter ISO country code indicating the country where the component represented by this CAD model is designed or manufactured (e.g., DEU, USA, CHN). Used for export control compliance (ITAR/EAR), customs declarations, and regional regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the CAD model record was first created in the PLM/PDM system. Provides the starting point for the models audit trail and lifecycle history. Corresponds to Teamcenter Creation Date metadata.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `design_owner` STRING COMMENT 'Name or employee identifier of the responsible design engineer who owns and maintains the CAD model. Accountable for model accuracy, revision control, and release approvals. Corresponds to the Teamcenter Owning User field.',
    `dfa_status` STRING COMMENT 'Current status of the Design for Assembly (DFA) analysis for this CAD model. Evaluates the ease of assembly, part count reduction opportunities, and assembly process compatibility. Relevant for assembly-type models and sub-assemblies.. Valid values are `not_started|in_progress|passed|failed|waived`',
    `dfm_status` STRING COMMENT 'Current status of the Design for Manufacturability (DFM) analysis for this CAD model. Indicates whether the design has been reviewed for manufacturing feasibility, cost optimization, and process compatibility. A passed status is typically required before release to production.. Valid values are `not_started|in_progress|passed|failed|waived`',
    `digital_twin_reference` STRING COMMENT 'Identifier linking this CAD model to its corresponding digital twin instance on the Siemens MindSphere IIoT platform. Enables real-time correlation between the design geometry and operational asset behavior for predictive maintenance and performance optimization.',
    `export_control_class` STRING COMMENT 'Export control classification code assigned to the CAD model, indicating whether the design data is subject to export regulations (e.g., ITAR USML category, EAR ECCN code, or EAR99 for unrestricted). Critical for controlling access to design data shared with international suppliers or subsidiaries.',
    `file_format` STRING COMMENT 'Native or neutral file format of the CAD model dataset (e.g., STEP, IGES, JT, NX native). Determines interoperability with downstream systems including CAM, FEA simulation, and supplier collaboration. STEP (ISO 10303) is the preferred neutral exchange format for cross-system sharing.. Valid values are `STEP|IGES|JT|NX|CATIA|SolidWorks|DXF|DWG|STL|OBJ|PDF|PARASOLID|Other`',
    `file_name` STRING COMMENT 'Full file name of the CAD model dataset as stored in the PLM/PDM vault, including file extension (e.g., motor_housing_v2.prt, drive_shaft_asm.CATProduct). Used for file retrieval, version tracking, and integration with CAM and simulation tools.',
    `file_size_mb` DECIMAL(18,2) COMMENT 'Size of the CAD model file in megabytes as stored in the PLM vault. Used for storage capacity planning, data migration scoping, and identifying oversized models that may impact system performance or collaboration efficiency.',
    `freeze_date` DATE COMMENT 'Date on which the CAD model was frozen, preventing further modifications. Typically aligned with production launch milestones (e.g., PPAP approval, SOP - Start of Production). A frozen model can only be changed via a formal ECO process.. Valid values are `^d{4}-d{2}-d{2}$`',
    `is_master_model` BOOLEAN COMMENT 'Boolean flag indicating whether this CAD model is designated as the master geometry model for the component or assembly. The master model is the authoritative source for all downstream derivations (drawings, simulations, CAM programs). Only one master model should exist per component revision.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent modification to the CAD model record in the PLM/PDM system. Used for change tracking, synchronization with downstream systems (SAP, MES), and audit compliance. Corresponds to Teamcenter Last Modified Date.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `mass_kg` DECIMAL(18,2) COMMENT 'Calculated mass of the component or assembly as derived from the CAD model geometry and assigned material properties, expressed in kilograms. Used for structural analysis, logistics weight calculations, BOM costing, and compliance with weight-sensitive design requirements.',
    `model_name` STRING COMMENT 'Human-readable descriptive name of the CAD/CAM model as defined by the design engineer. Typically reflects the component or assembly name (e.g., Motor Housing Assembly, Drive Shaft Bracket). Corresponds to Teamcenter Item Name.',
    `model_number` STRING COMMENT 'Business-assigned alphanumeric identifier for the CAD/CAM model as registered in the PLM/PDM system. Used for cross-referencing with BOM, ECN/ECO, and engineering documentation. Corresponds to the Teamcenter Item ID.. Valid values are `^[A-Z0-9-.]{3,50}$`',
    `model_type` STRING COMMENT 'Classification of the CAD model by its geometric or representational type. Determines the applicable CAD tools, downstream processes (e.g., CAM toolpath generation, FEA simulation), and BOM linkage. 3d_solid is the primary type for CNC machining and DFM analysis.. Valid values are `3d_solid|3d_surface|2d_drawing|assembly|simulation|wiring_diagram|schematic|point_cloud|mesh`',
    `obsolescence_date` DATE COMMENT 'Date on which the CAD model revision was marked as obsolete, indicating it has been superseded by a newer revision or the component has been discontinued. Used for lifecycle management, archive planning, and BOM cleanup.. Valid values are `^d{4}-d{2}-d{2}$`',
    `owning_group` STRING COMMENT 'Name of the engineering team, department, or organizational group responsible for the CAD model (e.g., Mechanical Design, Electrical Engineering, Automation Systems). Used for workload distribution, access control, and organizational reporting in PLM.',
    `primary_material` STRING COMMENT 'Name or code of the primary engineering material assigned to the CAD model (e.g., Aluminum 6061-T6, Stainless Steel 316L, ABS Plastic). Drives material requirements planning (MRP), cost estimation, and compliance checks for REACH/RoHS regulations.',
    `product_line` STRING COMMENT 'Name of the product line or product family to which the designed component or assembly belongs (e.g., Automation Systems, Electrification Solutions, Smart Infrastructure). Supports portfolio-level reporting and PLM product structure navigation.',
    `project_code` STRING COMMENT 'Alphanumeric code identifying the engineering project or program under which the CAD model was created. Links the model to project planning, resource allocation, and CAPEX tracking in SAP PS (Project System). Supports APQP phase tracking.. Valid values are `^[A-Z0-9-]{3,30}$`',
    `release_date` DATE COMMENT 'Date on which the CAD model revision was formally released (approved and promoted to released lifecycle state) in the PLM system. Marks the point at which the design is authorized for use in manufacturing, procurement, and BOM structures.. Valid values are `^d{4}-d{2}-d{2}$`',
    `revision` STRING COMMENT 'Alphanumeric revision identifier indicating the version of the CAD model (e.g., A, B, C, 01, 02). Incremented upon each approved engineering change. Corresponds to Teamcenter Item Revision ID and is critical for configuration management and BOM accuracy.. Valid values are `^[A-Z0-9]{1,10}$`',
    `surface_finish` STRING COMMENT 'Required surface finish or roughness specification for the component as defined in the CAD model (e.g., Ra 1.6 µm, Anodized, Powder Coated). Drives manufacturing process selection, quality inspection criteria, and supplier specifications.',
    `tolerance_class` STRING COMMENT 'General tolerance class applied to the CAD model for dimensions not individually toleranced (e.g., Fine, Medium, Coarse per ISO 2768). Determines manufacturing precision requirements, process selection, and inspection rigor. Critical for DFM analysis.. Valid values are `fine|medium|coarse|very_coarse|custom`',
    `unit_of_measure` STRING COMMENT 'Base unit of measurement used in the CAD model geometry (e.g., MM for millimeters, IN for inches). Critical for dimensional accuracy, interoperability with CAM systems, and compliance with regional engineering standards. Must be consistent across all models in an assembly.. Valid values are `MM|CM|M|IN|FT|DEG`',
    CONSTRAINT pk_cad_model PRIMARY KEY(`cad_model_id`)
) COMMENT 'Master record for CAD/CAM design models and 3D geometry files managed within the PLM/PDM system. Captures model number, CAD tool (e.g., NX, CATIA, SolidWorks), file format, revision, lifecycle state (in-work, released, frozen), design owner, associated component or assembly, model type (3D solid, 2D drawing, simulation), and digital twin linkage. Sourced from Siemens Teamcenter Document Management.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`eco` (
    `eco_id` BIGINT COMMENT 'Unique surrogate identifier for the Engineering Change Order record in the lakehouse silver layer. Serves as the primary key for all downstream joins and lineage tracking.',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: eco.ecn_number is a STRING reference to the parent ECN that this ECO implements. The ECO is the formal authorization child of the ECN (ECN proposes, ECO authorizes implementation). Replacing with FK e',
    `actual_cost` DECIMAL(18,2) COMMENT 'Actual total cost incurred to implement the engineering change, captured upon completion. Compared against estimated_cost for variance analysis and continuous improvement of change cost estimation accuracy.',
    `affected_bom_revisions` STRING COMMENT 'Comma-separated list or description of the Bill of Materials (BOM) revision identifiers that are created or updated as a result of this ECO. Provides traceability between the change order and specific BOM versions in SAP PP and Teamcenter.',
    `affected_drawing_revisions` STRING COMMENT 'Comma-separated list or description of the engineering drawing revision identifiers (CAD/CAM drawings) that are updated as part of this ECO. Ensures drawing version control traceability in Teamcenter PDM.',
    `affected_part_numbers` STRING COMMENT 'Comma-separated list of material/part numbers (SAP material numbers or Teamcenter item IDs) directly affected by this engineering change. Used for impact analysis and to identify all downstream BOM assemblies requiring update.',
    `affected_routing_revisions` STRING COMMENT 'Comma-separated list or description of the production routing (Bill of Process/BoP) revision identifiers updated by this ECO. Routing changes affect work center assignments, operation sequences, and standard times in SAP PP.',
    `approved_date` DATE COMMENT 'The date on which the ECO received final authorization to proceed with implementation. Marks the transition from approval workflow to release for manufacturing execution.. Valid values are `^d{4}-d{2}-d{2}$`',
    `change_class` STRING COMMENT 'Severity classification of the engineering change. Class 1 (Major) changes affect form, fit, or function and require full PPAP re-submission; Class 2 (Minor) changes require limited validation; Class 3 (Administrative) changes are documentation-only.. Valid values are `class_1_major|class_2_minor|class_3_administrative`',
    `change_type` STRING COMMENT 'Classification of the type of engineering change being implemented. Determines which downstream systems (SAP PP BOM, Teamcenter drawings, routing) must be updated and which approval workflows are triggered.. Valid values are `design_change|process_change|material_substitution|drawing_revision|bom_revision|routing_revision|specification_change|regulatory_compliance|cost_reduction|quality_improvement|safety_improvement|customer_request`',
    `completed_date` DATE COMMENT 'The actual date on which all implementation tasks for the ECO were confirmed complete, including BOM updates, drawing revisions, routing changes, and shop floor verification. Used for cycle time analysis.. Valid values are `^d{4}-d{2}-d{2}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary country where this engineering change is being implemented. Supports multi-country regulatory compliance tracking and regional reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated and actual cost fields (e.g., USD, EUR, GBP). Supports multi-currency reporting for multinational operations.. Valid values are `^[A-Z]{3}$`',
    `customer_approval_required` BOOLEAN COMMENT 'Indicates whether formal written customer approval must be obtained before the engineering change can be implemented. Applicable for changes to customer-specific designs or regulated products under customer quality agreements.. Valid values are `true|false`',
    `customer_notification_required` BOOLEAN COMMENT 'Indicates whether the customer must be formally notified of this engineering change prior to or upon implementation. Required for changes affecting form, fit, or function on customer-specific products or under contractual SLA obligations.. Valid values are `true|false`',
    `description` STRING COMMENT 'Detailed narrative describing the technical change being implemented, including what is changing, why it is changing, and the expected outcome. Supports traceability and regulatory audit requirements.',
    `disposition_of_stock` STRING COMMENT 'Defines how existing finished goods and raw material inventory affected by the change are to be handled. Determines whether pre-change stock can be consumed, must be reworked, or must be scrapped.. Valid values are `use_as_is|rework|scrap|return_to_supplier|hold_for_review|consume_before_effectivity`',
    `disposition_of_wip` STRING COMMENT 'Defines how existing Work in Progress (WIP) inventory and in-process assemblies are to be handled at the time the engineering change becomes effective. Drives shop floor instructions and material disposition in SAP MM/PP.. Valid values are `use_as_is|rework|scrap|return_to_supplier|hold_for_review`',
    `effectivity_date` DATE COMMENT 'The calendar date on which the engineering change becomes effective in production, applicable when effectivity_type is date_based. Used to schedule BOM and routing updates in SAP PP and Teamcenter.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effectivity_lot_number_from` STRING COMMENT 'The starting production lot number from which the engineering change becomes effective, applicable when effectivity_type is lot_based. All lots at or above this number incorporate the change.',
    `effectivity_serial_number_from` STRING COMMENT 'The starting serial number from which the engineering change becomes effective, applicable when effectivity_type is serial_number_based. All units with serial numbers at or above this value incorporate the change.',
    `effectivity_type` STRING COMMENT 'Defines the method by which the engineering change becomes effective in production. Date-based effectivity triggers on a calendar date; serial-number-based triggers at a specific unit; lot-based triggers at a specific production lot. Drives SAP PP BOM and routing effectivity configuration.. Valid values are `date_based|serial_number_based|lot_based|unit_based|immediate`',
    `estimated_cost` DECIMAL(18,2) COMMENT 'Estimated total cost to implement the engineering change, including engineering labor, tooling, material scrap/rework, and validation costs. Used for change impact assessment, CAPEX/OPEX planning, and ROI analysis.',
    `implementation_deadline` DATE COMMENT 'The mandatory completion date by which all BOM revisions, drawing revisions, routing revisions, and shop floor updates must be fully implemented. Used for scheduling, escalation management, and compliance tracking.. Valid values are `^d{4}-d{2}-d{2}$`',
    `number` STRING COMMENT 'Human-readable, business-facing identifier for the Engineering Change Order as assigned by the PLM/PDM system (Siemens Teamcenter). Used for cross-system referencing in SAP PP, shop floor communications, and audit trails.. Valid values are `^ECO-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `originating_department` STRING COMMENT 'The organizational department that initiated the engineering change request (e.g., Product Engineering, Quality, Manufacturing, Customer Service). Used for change volume analytics and departmental accountability reporting.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or facilities where the engineering change must be implemented. Supports multi-plant rollout coordination and plant-specific BOM/routing updates.',
    `ppap_level` STRING COMMENT 'The PPAP submission level required for this engineering change, ranging from Level 1 (Part Submission Warrant only) to Level 5 (full documentation retained at customer location). Determined by customer requirements and change classification.. Valid values are `level_1|level_2|level_3|level_4|level_5|not_applicable`',
    `ppap_required` BOOLEAN COMMENT 'Indicates whether a Production Part Approval Process (PPAP) submission is required for this engineering change, typically mandated for Class 1 (Major) changes affecting form, fit, or function for automotive or regulated customers.. Valid values are `true|false`',
    `priority` STRING COMMENT 'Business priority assigned to the ECO, reflecting urgency of implementation. Critical priority ECOs (e.g., safety or regulatory-driven) are fast-tracked through approval and implementation workflows.. Valid values are `critical|high|medium|low`',
    `reason_code` STRING COMMENT 'Standardized reason code indicating the primary business driver for the engineering change. Used for root cause analysis, change trend reporting, and CAPA linkage.. Valid values are `safety|regulatory_compliance|quality_defect|cost_reduction|customer_request|design_improvement|supplier_change|obsolescence|warranty_issue|manufacturing_issue|drawing_error|other`',
    `regulatory_driven` BOOLEAN COMMENT 'Indicates whether this engineering change is mandated by a regulatory requirement (e.g., RoHS/REACH compliance, CE Marking, UL certification, OSHA safety requirement). Regulatory-driven ECOs receive elevated priority and mandatory completion tracking.. Valid values are `true|false`',
    `regulatory_reference` STRING COMMENT 'Specific regulatory standard, directive, or requirement number that mandates this engineering change (e.g., RoHS 2011/65/EU, REACH SVHC List Update, CE Marking EN 60204-1). Populated only when regulatory_driven is true.',
    `released_date` DATE COMMENT 'The date on which the ECO was formally released to manufacturing and the updated BOM/routing/drawings were published in SAP PP and Teamcenter for shop floor execution.. Valid values are `^d{4}-d{2}-d{2}$`',
    `requested_date` DATE COMMENT 'The date on which the ECO was formally requested or initiated. Used for lead time analysis and change management performance reporting.. Valid values are `^d{4}-d{2}-d{2}$`',
    `responsible_engineer` STRING COMMENT 'Name or employee identifier of the lead engineer accountable for coordinating and completing the ECO implementation. This is the primary point of contact for all technical questions related to the change.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this ECO record was sourced (e.g., Siemens Teamcenter PLM, SAP S/4HANA). Supports data lineage tracking and reconciliation in the lakehouse silver layer.. Valid values are `teamcenter|sap_s4hana|manual|other`',
    `source_system_code` STRING COMMENT 'The native identifier of this ECO record in the originating operational system (e.g., Teamcenter Change Order UID or SAP Change Number). Enables bidirectional traceability between the lakehouse and the system of record.',
    `status` STRING COMMENT 'Current lifecycle status of the ECO, tracking its progression from initial drafting through approval, release to manufacturing, implementation, and closure. Drives workflow routing in Teamcenter and SAP PP.. Valid values are `draft|submitted|under_review|approved|released|in_implementation|completed|cancelled|on_hold`',
    `title` STRING COMMENT 'Short, descriptive title summarizing the nature and scope of the engineering change. Used in dashboards, approval workflows, and stakeholder communications.',
    CONSTRAINT pk_eco PRIMARY KEY(`eco_id`)
) COMMENT 'Engineering Change Order record representing the formal authorization and implementation instruction derived from an approved ECN. Captures ECO number, linked ECN, implementation scope (affected BOM revisions, drawing revisions, routing revisions), effectivity type (date-based, serial number-based, lot-based), implementation deadline, responsible engineer, and completion status. Drives BOM and routing updates in SAP PP and Teamcenter.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`change_affected_item` (
    `change_affected_item_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each association record between an engineering change (ECN/ECO) and a specific affected item (component, BOM, drawing, routing, or document) within the Siemens Teamcenter PLM change management module.',
    `bom_line_id` BIGINT COMMENT 'Foreign key linking to engineering.bom_line. Business justification: When an ECN/ECO affects a specific BOM component (the most common change scenario in manufacturing), the change_affected_item record should reference the specific bom_line being changed. This provides',
    `contract_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_contract. Business justification: Engineering change affected items for purchased parts must reference the active procurement contract. Change control boards use this link to assess commercial impact of design changes and trigger cont',
    `control_plan_id` BIGINT COMMENT 'Foreign key linking to quality.control_plan. Business justification: Engineering changes that affect manufacturing processes require control plan updates — the affected item record links to the impacted control plan. This is a mandatory step in engineering change impac',
    `drawing_id` BIGINT COMMENT 'Foreign key linking to engineering.drawing. Business justification: When an ECN/ECO affects a specific engineering drawing, the change_affected_item record should reference the specific drawing being changed. This provides direct traceability from the change managemen',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: change_affected_item.ecn_number is a STRING reference to the ECN this affected item is associated with. change_affected_item is the association record linking ECNs/ECOs to affected items. Replacing wi',
    `eco_id` BIGINT COMMENT 'Foreign key linking to engineering.eco. Business justification: change_affected_item.eco_number is a STRING reference to the ECO this affected item is associated with. Replacing with FK eco_id → eco.eco_id enforces referential integrity for the ECO-to-affected-ite',
    `inspection_plan_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_plan. Business justification: Engineering changes affect inspection plans when component specifications change. Change management tracks which inspection plans require updates to reflect new tolerances or characteristics.',
    `affected_plant_codes` STRING COMMENT 'Comma-separated list of SAP plant codes for all manufacturing facilities where this affected item is produced or used, and where the engineering change must be implemented. Supports global change rollout coordination across multinational manufacturing sites.',
    `bom_position` STRING COMMENT 'The BOM line item position or component item number within the parent assemblys Bill of Materials where this affected item resides. Enables precise identification of the structural location of the change within the product hierarchy.',
    `capa_reference` STRING COMMENT 'Reference number of the associated Corrective and Preventive Action (CAPA) record in the Quality Management System (QMS) that triggered or is linked to this engineering change for the affected item. Enables traceability between quality events and engineering change actions.',
    `change_action` STRING COMMENT 'The specific action to be performed on the affected item as a result of the engineering change. Revise updates an existing item to a new revision; Create introduces a new item; Obsolete retires an item from active use; Supersede replaces one item with another; Incorporate merges changes into an existing revision; Cancel voids a previously planned change.. Valid values are `revise|create|obsolete|supersede|incorporate|cancel`',
    `change_description` STRING COMMENT 'Detailed narrative description of what specifically changed for this affected item, including the nature of the modification, the technical rationale, and any relevant engineering justification. Provides the human-readable explanation of the change for engineers, quality auditors, and regulatory reviewers.',
    `change_reason_code` STRING COMMENT 'Standardized code categorizing the primary business reason driving the engineering change for this affected item. Supports root cause analysis, change trend reporting, and CAPA (Corrective and Preventive Action) linkage in the QMS.. Valid values are `design_error|customer_requirement|regulatory_compliance|cost_reduction|supplier_change|quality_improvement|obsolescence|safety|performance|standardization|other`',
    `cost_impact_category` STRING COMMENT 'High-level classification of the financial impact of the engineering change on this affected item. Indicates whether the change is expected to reduce, maintain, or increase the cost of the item, supporting financial impact assessment and CAPEX/OPEX planning.. Valid values are `cost_reduction|cost_neutral|cost_increase|unknown`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this change affected item association record was created in the PLM/PDM system. Provides the audit trail entry point for the change record lifecycle.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated cost impact value (e.g., USD, EUR, GBP, CNY). Supports multi-currency financial reporting in global manufacturing operations.. Valid values are `^[A-Z]{3}$`',
    `disposition_action` STRING COMMENT 'The required disposition for existing inventory or work-in-progress (WIP) stock of the affected item at the time the change is implemented. Determines whether existing stock should be used as-is, reworked to the new revision, scrapped, returned to supplier, retrofitted in the field, or held pending further review.. Valid values are `use_as_is|rework|scrap|return_to_supplier|retrofit|hold_for_review`',
    `effectivity_date` DATE COMMENT 'The calendar date from which the engineering change becomes effective for this affected item when date-based effectivity is used. Drives production scheduling, procurement cutover, and inventory disposition decisions in SAP S/4HANA MRP.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effectivity_serial_number` STRING COMMENT 'The manufacturing serial number from which the engineering change becomes effective when serial-number-based effectivity is used. Ensures that units produced at or after this serial number incorporate the change, while earlier units retain the previous configuration.',
    `effectivity_type` STRING COMMENT 'Defines the method by which the engineering change becomes effective for this item. Date effectivity applies the change from a specific calendar date; serial number effectivity applies from a specific unit serial number; lot effectivity applies from a specific production lot; unit effectivity applies to specific unit numbers; immediate applies without a scheduled effectivity point.. Valid values are `date_effectivity|serial_number_effectivity|lot_effectivity|unit_effectivity|immediate`',
    `estimated_cost_impact` DECIMAL(18,2) COMMENT 'The estimated financial impact (positive or negative) of implementing the engineering change on this affected item, expressed in the transaction currency. Negative values indicate cost savings; positive values indicate cost increases. Used for change approval financial justification.',
    `form_fit_function_flag` BOOLEAN COMMENT 'Indicates whether the engineering change affects the form, fit, or function of the affected item. A true value triggers mandatory customer notification, PPAP re-submission, and regulatory re-evaluation workflows in accordance with customer-specific requirements and quality standards.. Valid values are `true|false`',
    `impact_level` STRING COMMENT 'Assessment of the severity and scope of the engineering change impact on this affected item. Critical changes affect form, fit, or function and may require customer notification or regulatory re-approval; major changes affect performance or interchangeability; minor changes are non-functional improvements; cosmetic changes affect appearance only.. Valid values are `critical|major|minor|cosmetic`',
    `implementation_date` DATE COMMENT 'The actual date on which the engineering change was physically implemented for this affected item in the production environment. Distinguishes the planned effectivity date from the actual execution date for change tracking and audit purposes.. Valid values are `^d{4}-d{2}-d{2}$`',
    `implementation_status` STRING COMMENT 'Current status of the engineering change implementation for this specific affected item. Tracks the lifecycle from initial identification through verification, enabling program managers and engineers to monitor change execution progress across all affected items.. Valid values are `pending|in_progress|implemented|verified|rejected|on_hold|cancelled`',
    `item_name` STRING COMMENT 'The descriptive name or title of the affected item (e.g., part description, drawing title, document name) as recorded in the PLM/PDM system. Provides human-readable identification alongside the item number.',
    `item_number` STRING COMMENT 'The unique part number, document number, or identifier of the specific item affected by the engineering change, as maintained in the PLM/PDM or ERP system (SAP S/4HANA MM or Teamcenter). This is the primary business key for the affected object.',
    `item_type` STRING COMMENT 'Classification of the item affected by the engineering change. Indicates whether the affected object is a component, assembly, Bill of Materials (BOM), engineering drawing, manufacturing routing, controlled document, tooling, specification, software artifact, or firmware image.. Valid values are `component|assembly|bom|drawing|routing|document|tool|specification|software|firmware`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time when this change affected item record was most recently updated in the PLM/PDM system. Supports change audit trails, data lineage tracking, and incremental data pipeline processing in the Databricks Silver Layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `ncr_reference` STRING COMMENT 'Reference number of the Non-Conformance Report (NCR) associated with this affected item change record. Links the engineering change to the specific quality non-conformance event that necessitated the design or process modification.',
    `new_revision` STRING COMMENT 'The revision identifier assigned to the affected item after the engineering change is implemented. Represents the updated configuration baseline and is used for release control and downstream BOM/routing updates.. Valid values are `^[A-Z0-9]{1,10}$`',
    `old_revision` STRING COMMENT 'The revision identifier (e.g., A, B, 01, REV-C) of the affected item prior to the engineering change being applied. Establishes the baseline from which the change is made and supports full revision history traceability.. Valid values are `^[A-Z0-9]{1,10}$`',
    `owning_plant_code` STRING COMMENT 'The SAP plant code or facility identifier of the manufacturing plant responsible for implementing the change on this affected item. Supports multi-plant change management and ensures the correct facility executes the change in global manufacturing operations.',
    `parent_item_number` STRING COMMENT 'The part number or identifier of the parent assembly or document that directly contains or references the affected item. Supports where-used analysis and impact assessment across the product structure when evaluating the scope of an engineering change.',
    `planned_implementation_date` DATE COMMENT 'The originally scheduled date for implementing the engineering change on this affected item. Used for program planning, resource scheduling, and on-time delivery tracking. Compared against the actual implementation date to measure change execution performance.. Valid values are `^d{4}-d{2}-d{2}$`',
    `regulatory_approval_required` BOOLEAN COMMENT 'Indicates whether the engineering change to this affected item requires formal approval from an external regulatory body (e.g., CE Marking re-assessment, UL re-certification, RoHS/REACH compliance re-evaluation) before the change can be released to production.. Valid values are `true|false`',
    `regulatory_approval_status` STRING COMMENT 'Current status of the regulatory approval process for the engineering change on this affected item. Tracks whether external certification or compliance re-evaluation has been initiated, submitted to the authority, approved, or rejected.. Valid values are `not_required|pending|submitted|approved|rejected|conditionally_approved`',
    `responsible_engineer` STRING COMMENT 'The name or employee identifier of the design or process engineer accountable for implementing and verifying the engineering change on this specific affected item. Establishes clear ownership for change execution and audit trail purposes.',
    `safety_critical_flag` BOOLEAN COMMENT 'Indicates whether the affected item is classified as safety-critical, requiring mandatory safety review, DFMEA/PFMEA update, and regulatory authority notification before the change can be implemented. Applies to items subject to CE Marking, UL certification, ISO 45001, or OSHA requirements.. Valid values are `true|false`',
    `sequence_number` STRING COMMENT 'Numeric sequence number defining the order in which affected items within the same ECN/ECO should be processed or implemented. Ensures correct sequencing of interdependent changes across multiple affected items within a single engineering change.. Valid values are `^[0-9]+$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this change affected item record originated. Supports data lineage tracking and multi-system reconciliation in the Databricks Lakehouse Silver Layer.. Valid values are `teamcenter|sap_s4hana|opcenter|manual`',
    `verification_date` DATE COMMENT 'The date on which verification of the engineering change was completed for this affected item. Used to confirm that the change has been validated before the item is released for full production use.. Valid values are `^d{4}-d{2}-d{2}$`',
    `verification_method` STRING COMMENT 'The engineering verification method required to confirm that the change has been correctly implemented and meets design intent for this affected item. First Article Inspection (FAI) is commonly required for safety-critical or form-fit-function changes.. Valid values are `test|inspection|analysis|demonstration|similarity|first_article_inspection|none`',
    `verification_status` STRING COMMENT 'Current status of the verification activity for this affected item following change implementation. Indicates whether the required verification (test, inspection, FAI) has been completed successfully, is in progress, has failed, or has been formally waived.. Valid values are `not_started|in_progress|passed|failed|waived`',
    CONSTRAINT pk_change_affected_item PRIMARY KEY(`change_affected_item_id`)
) COMMENT 'Association record linking an ECN or ECO to each specific item (component, BOM, drawing, routing, document) affected by the engineering change. Captures the affected item type, item identifier, old revision, new revision, change action (revise, obsolete, create), and implementation status. Enables full traceability of what changed, when, and why across the product structure.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`dfmea` (
    `dfmea_id` BIGINT COMMENT 'Unique system-generated identifier for the DFMEA record within the enterprise data platform. Serves as the primary key for all downstream references and linkages.',
    `cad_model_id` BIGINT COMMENT 'Foreign key linking to engineering.cad_model. Business justification: Design FMEA analyzes failure modes of specific components and assemblies whose geometry is defined in CAD models. Linking dfmea to cad_model provides direct traceability from the design risk analysis ',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: dfmea.ecn_reference is a STRING reference to the ECN that triggered or is associated with this DFMEA update. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for design ri',
    `engineering_bom_id` BIGINT COMMENT 'Foreign key linking to engineering.engineering_bom. Business justification: DFMEA is conducted at the assembly/sub-assembly level defined in the engineering BOM. Linking dfmea to engineering_bom identifies which product assembly the design risk analysis covers, enabling BOM-l',
    `fmea_id` BIGINT COMMENT 'Foreign key linking to quality.fmea. Business justification: Design FMEA is a specialized type of FMEA managed in quality systems. Engineering references the quality FMEA framework for risk assessment methodology and tracking.',
    `product_specification_id` BIGINT COMMENT 'Foreign key linking to engineering.product_specification. Business justification: DFMEA failure modes are directly tied to product specifications — a failure mode represents the inability to meet a specific functional or performance specification. Linking dfmea to product_specifica',
    `action_completion_date` DATE COMMENT 'Actual date on which the recommended action was completed and verified. Used to measure APQP schedule adherence and close open DFMEA action items.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `action_priority` STRING COMMENT 'Action Priority classification (H=High, M=Medium, L=Low) per the AIAG-VDA FMEA Handbook, used alongside RPN to determine urgency of recommended actions. High priority requires immediate action regardless of RPN value.. Valid values are `H|M|L`',
    `action_taken` STRING COMMENT 'Description of the actual corrective or preventive action implemented to address the failure mode. Recorded after completion to close the DFMEA action loop and support CAPA documentation.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the engineering manager or quality authority who formally approved the DFMEA document for release.',
    `apqp_phase` STRING COMMENT 'The APQP phase during which this DFMEA was created or last updated. Phase 1=Plan and Define, Phase 2=Product Design and Development, Phase 3=Process Design and Development, Phase 4=Product and Process Validation, Phase 5=Feedback Assessment and Corrective Action.. Valid values are `phase_1|phase_2|phase_3|phase_4|phase_5`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the engineering site or manufacturing location where the design is being developed. Supports multinational regulatory compliance tracking (e.g., CE Marking for EU, UL for USA).. Valid values are `^[A-Z]{3}$`',
    `customer_name` STRING COMMENT 'Name of the external customer or internal program for which this DFMEA is being prepared. Relevant for PPAP submissions and customer-specific requirements (CSR).',
    `design_control_detection` STRING COMMENT 'Current design controls in place to detect the failure mode or cause before the product reaches the customer (e.g., prototype testing, FEA simulation, design review checklist, First Article Inspection (FAI)). Addresses detection-type controls per AIAG-VDA Step 5.',
    `design_control_prevention` STRING COMMENT 'Current design controls in place to prevent the failure cause from occurring (e.g., design standard XYZ applied, material specification review, DFM analysis completed). Addresses prevention-type controls per AIAG-VDA Step 5.',
    `detection_rating` STRING COMMENT 'Numeric rating (1–10) assessing the ability of current design controls to detect the failure cause or failure mode before product release. A rating of 10 indicates no detection capability; 1 indicates near-certain detection.. Valid values are `^([1-9]|10)$`',
    `failure_cause` STRING COMMENT 'The specific design deficiency or root cause mechanism that leads to the failure mode (e.g., insufficient wall thickness, incorrect material specification, inadequate clearance between mating parts). Identified through DFMEA root cause analysis.',
    `failure_effect` STRING COMMENT 'The consequence of the failure mode on the next higher-level assembly, end customer, or end user. Describes what the customer experiences if the failure mode occurs (e.g., loss of motor control, vehicle does not start, operator injury).',
    `failure_mode` STRING COMMENT 'The specific manner in which the design element could potentially fail to meet its intended function or design intent (e.g., fracture under load, electrical short circuit, corrosion of contact surface). Core DFMEA field per AIAG-VDA Step 3.',
    `last_revised_date` DATE COMMENT 'Date of the most recent revision to the DFMEA document. Tracks the currency of the risk assessment and supports document control requirements.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `model_year` STRING COMMENT 'The model year or product generation to which this DFMEA applies. Used for product lifecycle tracking and APQP milestone alignment.. Valid values are `^[0-9]{4}$`',
    `number` STRING COMMENT 'Business-assigned alphanumeric identifier for the DFMEA document, used for cross-referencing in APQP deliverables, PPAP packages, and Teamcenter PLM. Unique within the organization.. Valid values are `^DFMEA-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `occurrence_rating` STRING COMMENT 'Numeric rating (1–10) estimating the likelihood that the failure cause will occur and result in the failure mode. A rating of 10 indicates near-certain occurrence; 1 indicates extremely unlikely. Based on historical data, design similarity, and engineering judgment.. Valid values are `^([1-9]|10)$`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or engineering site responsible for the product design covered by this DFMEA. Supports multi-site and multinational operations.',
    `ppap_submission_required` BOOLEAN COMMENT 'Indicates whether this DFMEA is required as part of a PPAP submission package to the customer. When true, the DFMEA must meet customer-specific requirements (CSR) for PPAP level compliance.. Valid values are `true|false`',
    `preparation_date` DATE COMMENT 'Date on which the DFMEA was initially prepared and documented. Used for APQP timeline tracking and document control.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `prepared_by` STRING COMMENT 'Name or employee identifier of the engineer or analyst who originally prepared and authored the DFMEA document.',
    `recommended_action` STRING COMMENT 'Specific corrective or preventive action recommended to reduce severity, occurrence, or detection ratings for high-priority failure modes. May include design changes, additional testing, material substitution, or tolerance revisions.',
    `regulatory_compliance_flag` BOOLEAN COMMENT 'Indicates whether this DFMEA addresses failure modes related to regulatory compliance requirements such as RoHS, REACH, CE Marking, UL certification, or OSHA/EPA mandates. Triggers mandatory compliance review workflow.. Valid values are `true|false`',
    `responsible_engineer` STRING COMMENT 'Name or employee identifier of the design engineer responsible for implementing the recommended action and updating the DFMEA. Assigned per AIAG-VDA Step 6 accountability requirements.',
    `revised_detection_rating` STRING COMMENT 'Updated detection rating after implementation of recommended actions. Reflects improved detection capability post-mitigation.. Valid values are `^([1-9]|10)$`',
    `revised_occurrence_rating` STRING COMMENT 'Updated occurrence rating after implementation of recommended actions. Reflects the reduced likelihood of the failure cause occurring post-mitigation.. Valid values are `^([1-9]|10)$`',
    `revised_rpn` STRING COMMENT 'Recalculated Risk Priority Number (Revised S × Revised O × Revised D) after corrective actions have been implemented. Used to confirm risk reduction and validate DFMEA closure.. Valid values are `^([1-9][0-9]{0,2}|1000)$`',
    `revised_severity_rating` STRING COMMENT 'Updated severity rating after implementation of recommended actions. Reflects the residual risk level post-mitigation. Compared against original severity to demonstrate risk reduction effectiveness.. Valid values are `^([1-9]|10)$`',
    `revision` STRING COMMENT 'Alphanumeric revision identifier indicating the current version of the DFMEA document (e.g., A, B, C, 01, 02). Incremented upon each approved Engineering Change Notice (ECN) or design update.. Valid values are `^[A-Z0-9]{1,5}$`',
    `rpn` STRING COMMENT 'Risk Priority Number calculated as the product of Severity × Occurrence × Detection ratings (S × O × D). Ranges from 1 to 1000. Used to prioritize failure modes requiring corrective action. Note: AIAG-VDA also uses Action Priority (AP) as a complementary risk metric.. Valid values are `^([1-9][0-9]{0,2}|1000)$`',
    `safety_critical` BOOLEAN COMMENT 'Indicates whether any failure mode in this DFMEA has a severity rating of 9 or 10, classifying it as safety-critical or regulatory-critical. Safety-critical DFMEAs require mandatory escalation and additional design validation per ISO 26262, IEC 61508, or applicable product safety standards.. Valid values are `true|false`',
    `scope_description` STRING COMMENT 'Narrative description of the specific component, assembly, or system covered by this DFMEA, including functional boundaries and interfaces considered in the analysis.',
    `scope_level` STRING COMMENT 'Defines the hierarchical level of the design analysis scope: component (individual part), subsystem (grouped components), assembly (full assembly), or system (complete product system). Determines the depth and breadth of the FMEA analysis.. Valid values are `component|subsystem|system|assembly`',
    `severity_rating` STRING COMMENT 'Numeric rating (1–10) indicating the seriousness of the failure effect on the customer or end user. A rating of 10 indicates a safety-critical failure with no warning; 1 indicates no discernible effect. Defined per AIAG-VDA severity criteria.. Valid values are `^([1-9]|10)$`',
    `status` STRING COMMENT 'Current lifecycle status of the DFMEA record: draft (initial creation), in_review (under engineering review), approved (formally approved and baselined), closed (all actions completed), obsolete (superseded by a newer revision).. Valid values are `draft|in_review|approved|closed|obsolete`',
    `target_completion_date` DATE COMMENT 'Planned date by which the recommended action must be completed and verified. Used for APQP milestone tracking and PPAP readiness assessment.. Valid values are `^[0-9]{4}-[0-9]{2}-[0-9]{2}$`',
    `teamcenter_document_code` STRING COMMENT 'Unique document identifier assigned by Siemens Teamcenter PLM for the DFMEA document object. Enables direct traceability to the authoritative source document in the PLM/PDM system.',
    `title` STRING COMMENT 'Descriptive title of the DFMEA document, typically referencing the product, component, or assembly being analyzed (e.g., Motor Drive Assembly DFMEA – Electrification Module).',
    CONSTRAINT pk_dfmea PRIMARY KEY(`dfmea_id`)
) COMMENT 'Design Failure Mode and Effects Analysis record capturing the structured risk assessment of potential design failures for a component or assembly. Records DFMEA number, revision, scope (component or system level), each failure mode, potential effect, severity rating, potential cause, occurrence rating, current design controls, detection rating, RPN (Risk Priority Number), recommended actions, and responsible engineer. Supports APQP and PPAP deliverables. Managed in Teamcenter and linked to quality domain.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`pfmea` (
    `pfmea_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each PFMEA record in the Databricks Silver Layer. Serves as the primary key for all downstream joins and lineage tracking.',
    `bop_id` BIGINT COMMENT 'Foreign key linking to engineering.bop. Business justification: Process FMEA is conducted for a specific Bill of Process (manufacturing routing). Linking pfmea to bop at the header level provides traceability from the process risk analysis to the complete process ',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: pfmea.ecn_reference is a STRING reference to the ECN associated with this PFMEA update. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for process risk analysis. ecn_ref',
    `fmea_id` BIGINT COMMENT 'Foreign key linking to quality.fmea. Business justification: Process FMEA is a specialized FMEA type managed in quality systems. Manufacturing engineering uses quality FMEA structure for process risk analysis and mitigation tracking.',
    `action_completion_date` DATE COMMENT 'Actual date on which the recommended action was completed and evidence of implementation was recorded. Used to close out action items in CAPA workflows and update the PFMEA with revised ratings.. Valid values are `^d{4}-d{2}-d{2}$`',
    `action_priority` STRING COMMENT 'AIAG-VDA 2019 Action Priority classification (High/Medium/Low) derived from the combination of Severity, Occurrence, and Detection ratings using the AP lookup table. Supersedes sole reliance on RPN for prioritization in the updated PFMEA methodology.. Valid values are `high|medium|low`',
    `action_responsibility` STRING COMMENT 'Name or role of the person or team responsible for implementing the recommended action. Used for accountability tracking in CAPA workflows and PFMEA review meetings.',
    `action_target_date` DATE COMMENT 'Target date by which the recommended action must be completed and verified. Monitored in SAP QM CAPA tracking and PFMEA review cycles to ensure timely risk mitigation.. Valid values are `^d{4}-d{2}-d{2}$`',
    `approval_date` DATE COMMENT 'Date on which the PFMEA document was formally approved and released for production use. Establishes the effective date for quality control plan alignment and PPAP submission records.. Valid values are `^d{4}-d{2}-d{2}$`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the quality or engineering authority who formally approved the PFMEA document for release. Required for PPAP Level 3/4 submission and customer-facing quality documentation.',
    `capa_number` STRING COMMENT 'Reference number of the linked Corrective and Preventive Action (CAPA) record in SAP QM or the Quality Management System (QMS). Establishes traceability between the PFMEA risk item and the formal corrective action workflow.. Valid values are `^CAPA-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `control_plan_number` STRING COMMENT 'Reference number of the associated SPC Control Plan that incorporates the detection controls and inspection frequencies derived from this PFMEA. Links PFMEA outputs to Siemens Opcenter quality inspection plans.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the PFMEA record was first created in the system. Used for audit trail, data lineage tracking, and PFMEA lifecycle reporting in the Databricks Silver Layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `current_detection_control` STRING COMMENT 'Description of existing process controls designed to detect the failure mode or failure cause before the product reaches the next operation or customer (e.g., In-process CMM inspection, Vision system check, SPC control chart monitoring).',
    `current_prevention_control` STRING COMMENT 'Description of existing process controls designed to prevent the failure cause or failure mode from occurring (e.g., Poka-Yoke fixture, Operator SOP training, Incoming material inspection). Supports Poka-Yoke and error-proofing documentation.',
    `detection_rating` STRING COMMENT 'Numeric rating (1–10) assessing the ability of current detection controls to identify the failure cause or failure mode before the product leaves the process. A rating of 1 indicates near-certain detection; 10 indicates no detection capability.. Valid values are `^([1-9]|10)$`',
    `failure_cause` STRING COMMENT 'Root cause or mechanism by which the failure mode could occur in the process. Describes the specific process deficiency, variation source, or error condition (e.g., Worn electrode tip, Operator setup error, Material hardness variation).',
    `failure_effect` STRING COMMENT 'Description of the consequence or impact of the failure mode on the next operation, end customer, or product quality. Used to justify the severity rating and drive prioritization of corrective actions.',
    `failure_mode` STRING COMMENT 'Description of the specific way in which the process could potentially fail to meet its intended function or process requirement. Core element of the PFMEA risk assessment (e.g., Insufficient weld penetration, Incorrect torque applied).',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the PFMEA record. Supports change detection in ETL pipelines, audit compliance, and version control within the Databricks Silver Layer.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lead` STRING COMMENT 'Name or employee identifier of the lead process engineer responsible for authoring, maintaining, and updating the PFMEA document. Primary point of contact for PFMEA-related quality inquiries.',
    `model_year` STRING COMMENT 'Model year or program year associated with the product or platform for which this PFMEA was developed. Used for APQP program tracking and PPAP submission documentation.. Valid values are `^[0-9]{4}$`',
    `next_review_date` DATE COMMENT 'Scheduled date for the next periodic review of the PFMEA to ensure it remains current with process changes, quality data trends, and engineering change orders. Supports proactive risk management per IATF 16949 requirements.. Valid values are `^d{4}-d{2}-d{2}$`',
    `number` STRING COMMENT 'Business-assigned document control number for the PFMEA, used for cross-referencing in quality management systems, Siemens Teamcenter PLM, and SAP QM. Follows the enterprise document numbering convention.. Valid values are `^PFMEA-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `occurrence_rating` STRING COMMENT 'Numeric rating (1–10) estimating the likelihood or frequency of the failure cause occurring during production. Based on historical process data, Statistical Process Control (SPC) data, or engineering judgment per AIAG-VDA criteria.. Valid values are `^([1-9]|10)$`',
    `plant_code` STRING COMMENT 'Code identifying the manufacturing plant or facility where the process being analyzed is executed. Supports multi-site PFMEA management and plant-level quality reporting across global operations.',
    `process_function` STRING COMMENT 'The intended function or purpose of the process step being analyzed, describing what the operation is designed to achieve (e.g., Join two steel components with specified weld penetration depth).',
    `process_step` STRING COMMENT 'Detailed description of the specific process step or sub-operation within the BoP operation being analyzed in this PFMEA record. Provides granular context for the failure mode analysis.',
    `recommended_action` STRING COMMENT 'Specific corrective or preventive action recommended to reduce the severity, occurrence, or detection rating of the identified failure mode. Drives CAPA initiation in SAP QM and Siemens Opcenter quality workflows.',
    `revised_detection_rating` STRING COMMENT 'Updated detection rating (1–10) after implementation of the recommended action. Reflects improved detection capability resulting from new inspection methods, SPC controls, or automated detection systems.. Valid values are `^([1-9]|10)$`',
    `revised_occurrence_rating` STRING COMMENT 'Updated occurrence rating (1–10) after implementation of the recommended action. Reflects the reduced likelihood of the failure cause occurring following process improvements or error-proofing measures.. Valid values are `^([1-9]|10)$`',
    `revised_rpn` STRING COMMENT 'Recalculated Risk Priority Number (Revised S × Revised O × Revised D) after completion of recommended actions. Demonstrates risk reduction effectiveness and supports PFMEA closure criteria.. Valid values are `^([1-9][0-9]{0,2}|1000)$`',
    `revised_severity_rating` STRING COMMENT 'Updated severity rating (1–10) after implementation of the recommended action. Reflects the residual risk level post-mitigation and is used to recalculate the revised RPN for the PFMEA record.. Valid values are `^([1-9]|10)$`',
    `revision` STRING COMMENT 'Alphanumeric revision identifier indicating the current version of the PFMEA document. Incremented upon each approved Engineering Change Notice (ECN) or process change that impacts the risk assessment.. Valid values are `^[A-Z]{1,3}$|^[0-9]{1,3}$`',
    `rpn` STRING COMMENT 'Risk Priority Number calculated as the product of Severity × Occurrence × Detection ratings (range 1–1000). Used to prioritize failure modes requiring corrective action. High RPN values trigger mandatory CAPA initiation per quality management policy.. Valid values are `^([1-9][0-9]{0,2}|1000)$`',
    `severity_rating` STRING COMMENT 'Numeric rating (1–10) assessing the seriousness of the failure effect on the customer or next process. A rating of 10 indicates a safety or regulatory compliance impact. Defined per AIAG-VDA severity evaluation criteria.. Valid values are `^([1-9]|10)$`',
    `status` STRING COMMENT 'Current lifecycle status of the PFMEA document. Controls workflow routing in Siemens Teamcenter PLM and determines whether the PFMEA is active for production use in Siemens Opcenter MES quality inspection plans.. Valid values are `draft|in_review|approved|released|obsolete|superseded`',
    `team_members` STRING COMMENT 'Comma-separated list of names or employee IDs of cross-functional team members who participated in the PFMEA development session. Documents team composition for APQP and PPAP submission requirements.',
    `title` STRING COMMENT 'Descriptive title of the PFMEA document, typically referencing the process, product family, or manufacturing operation being analyzed (e.g., Welding Process PFMEA – Automation Frame Assembly).',
    `work_center` STRING COMMENT 'SAP work center or Opcenter resource identifier where the manufacturing operation is performed. Provides traceability from the PFMEA risk item to the physical production resource on the shop floor.',
    CONSTRAINT pk_pfmea PRIMARY KEY(`pfmea_id`)
) COMMENT 'Process Failure Mode and Effects Analysis record capturing the structured risk assessment of potential process failures for each manufacturing operation in the Bill of Process. Records PFMEA number, revision, linked BOP operation, failure mode, potential effect on product quality, severity, potential cause, occurrence, current process controls, detection rating, RPN, recommended actions, and CAPA linkage. Feeds SPC control plans and Opcenter quality inspection plans.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`plm_lifecycle_state` (
    `plm_lifecycle_state_id` BIGINT COMMENT 'Unique surrogate identifier for each authorized lifecycle state record within the Teamcenter PLM governance framework.',
    `lifecycle_id` BIGINT COMMENT 'Foreign key linking to product.lifecycle. Business justification: PLM lifecycle states in engineering must map to the commercial product lifecycle (introduction, growth, maturity, end-of-life). This synchronization drives release gates, obsolescence planning, and af',
    `allowed_transitions` STRING COMMENT 'Pipe-delimited list of target state codes to which a PLM object may transition from this state (e.g., IN_REVIEW|RELEASED|OBSOLETE). Defines the authorized state machine edges for workflow enforcement.',
    `applicable_object_types` STRING COMMENT 'Pipe-delimited list of PLM-managed object types to which this lifecycle state applies (e.g., Component|BOM|Drawing|CAD_Model|Document). Governs which object classes can be assigned this state.',
    `apqp_phase_alignment` STRING COMMENT 'Maps this lifecycle state to the corresponding APQP phase, enabling traceability between PLM object maturity and the formal product quality planning process used for new product introduction.. Valid values are `phase_1_plan_define|phase_2_product_design|phase_3_process_design|phase_4_product_process_validation|phase_5_launch|not_applicable`',
    `color_code_hex` STRING COMMENT 'Hexadecimal color code used to visually represent this lifecycle state in PLM dashboards, engineering portals, and reporting tools. Supports intuitive visual differentiation of product data maturity stages.. Valid values are `^#[0-9A-Fa-f]{6}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this lifecycle state configuration record was first created in the data product. Provides audit trail for governance and compliance purposes.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `downstream_system_trigger` STRING COMMENT 'Identifies downstream operational systems that are triggered upon a PLM object entering this lifecycle state (e.g., SAP_MM_Material_Master|SAP_PP_BOM|Opcenter_MES). Supports IT/OT convergence and PLM-ERP integration governance.',
    `ecn_required_for_entry` BOOLEAN COMMENT 'Indicates whether a valid Engineering Change Notice (ECN) or Engineering Change Order (ECO) must be referenced before a PLM object can be transitioned into this lifecycle state. Enforces formal change control governance.. Valid values are `true|false`',
    `ecn_required_for_exit` BOOLEAN COMMENT 'Indicates whether a valid Engineering Change Notice (ECN) or Engineering Change Order (ECO) must be referenced to transition a PLM object out of this lifecycle state. Typically applies to released or frozen states.. Valid values are `true|false`',
    `effective_from_date` DATE COMMENT 'Date from which this lifecycle state configuration is valid and available for use in PLM workflows. Supports versioned governance of lifecycle state definitions over time.. Valid values are `^d{4}-d{2}-d{2}$`',
    `effective_to_date` DATE COMMENT 'Date after which this lifecycle state configuration is no longer valid for new PLM object assignments. Null indicates the state is currently active with no planned expiry.. Valid values are `^d{4}-d{2}-d{2}$`',
    `export_control_check_required` BOOLEAN COMMENT 'Indicates whether an export control classification review (e.g., EAR, ITAR, dual-use goods assessment) must be completed before a PLM object can be transitioned into this lifecycle state.. Valid values are `true|false`',
    `icon_reference` STRING COMMENT 'Reference identifier or file path for the icon image associated with this lifecycle state in the PLM user interface. Used for visual representation in Teamcenter and integrated engineering portals.',
    `is_frozen_state` BOOLEAN COMMENT 'Indicates whether PLM objects in this state are frozen (read-only) and cannot be directly modified. Changes must be initiated via an Engineering Change Notice (ECN) or Engineering Change Order (ECO) process.. Valid values are `true|false`',
    `is_initial_state` BOOLEAN COMMENT 'Indicates whether this lifecycle state is the default starting state assigned to newly created PLM objects. Only one state per applicable object type should be flagged as the initial state.. Valid values are `true|false`',
    `is_released_state` BOOLEAN COMMENT 'Indicates whether this lifecycle state constitutes a formal release milestone, meaning the PLM object is authorized for use in production, procurement, or downstream processes such as BOM activation or MES execution.. Valid values are `true|false`',
    `is_terminal_state` BOOLEAN COMMENT 'Indicates whether this lifecycle state is a terminal (end) state from which no further forward transitions are permitted (e.g., Obsolete, Archived). Terminal states represent the end of the active product data lifecycle.. Valid values are `true|false`',
    `language_code` STRING COMMENT 'ISO 639-1 language code for the locale in which the state_name and state_description are expressed (e.g., en, de, zh-CN). Supports multinational PLM deployments with multi-language state label requirements.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this lifecycle state configuration record. Used for change tracking, data lineage, and incremental data pipeline processing.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `maturity_level` STRING COMMENT 'Standardized maturity level classification associated with this lifecycle state, indicating the degree of completeness and validation of the product data. Used for portfolio-level maturity reporting and APQP phase alignment.. Valid values are `concept|preliminary|detailed|validated|production_ready|obsolete`',
    `max_dwell_days` STRING COMMENT 'Maximum number of calendar days a PLM object is permitted to remain in this lifecycle state before an escalation or alert is triggered. Supports governance of stale or stuck product data records.. Valid values are `^[0-9]+$`',
    `minimum_approver_count` STRING COMMENT 'Minimum number of distinct approvers required to authorize a transition into this lifecycle state. Supports multi-signatory approval requirements for safety-critical or regulatory-relevant product data.. Valid values are `^[0-9]+$`',
    `notification_recipient_roles` STRING COMMENT 'Pipe-delimited list of organizational roles that receive automated notifications upon a PLM object entering this lifecycle state (e.g., Procurement|Manufacturing_Engineering|Quality_Assurance).',
    `notification_required` BOOLEAN COMMENT 'Indicates whether automated notifications must be sent to stakeholders (e.g., engineering team, quality, procurement) when a PLM object transitions into this lifecycle state.. Valid values are `true|false`',
    `plm_workflow_template_name` STRING COMMENT 'Name of the Teamcenter PLM workflow template associated with transitions into this lifecycle state. Identifies the formal approval and review workflow process definition used to govern state entry.',
    `ppap_required` BOOLEAN COMMENT 'Indicates whether a Production Part Approval Process (PPAP) submission is required as a prerequisite for transitioning a PLM object into this lifecycle state. Relevant for states representing production readiness.. Valid values are `true|false`',
    `quality_gate_required` BOOLEAN COMMENT 'Indicates whether a formal quality gate review (e.g., APQP phase gate, design review, DFMEA completion check) must be passed before a PLM object can enter this lifecycle state.. Valid values are `true|false`',
    `regulatory_review_required` BOOLEAN COMMENT 'Indicates whether regulatory compliance review (e.g., CE Marking, RoHS/REACH, UL certification, export control classification) must be completed before a PLM object can enter this lifecycle state.. Valid values are `true|false`',
    `required_approval_roles` STRING COMMENT 'Pipe-delimited list of organizational roles or job functions that must provide approval before a PLM object can enter this lifecycle state (e.g., Design_Engineer|Quality_Manager|Chief_Engineer). Enforces the approval governance matrix.',
    `sequence_order` STRING COMMENT 'Numeric ordering value that defines the canonical progression sequence of lifecycle states from concept through obsolescence. Used for sorting and maturity progression reporting.. Valid values are `^[0-9]+$`',
    `sla_transition_days` STRING COMMENT 'Target number of business days within which a PLM object should complete the review and approval process to transition out of this lifecycle state. Used for engineering workflow performance monitoring against SLA targets.. Valid values are `^[0-9]+$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this lifecycle state configuration was sourced (e.g., Teamcenter). Supports data lineage tracking in the Databricks Silver Layer lakehouse.. Valid values are `Teamcenter|SAP_S4HANA|Manual|Other`',
    `state_category` STRING COMMENT 'High-level category grouping lifecycle states for reporting and analytics. Enables aggregation of states into broader maturity phases (e.g., all review-type states grouped under review).. Valid values are `concept|development|review|approved|released|production|obsolete|archived`',
    `state_code` STRING COMMENT 'Short alphanumeric code uniquely identifying the lifecycle state within the PLM system (e.g., CONCEPT, IN_REVIEW, RELEASED, OBSOLETE). Used as the business key for state lookups and workflow routing.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `state_description` STRING COMMENT 'Detailed narrative description of the lifecycle state, including its business meaning, entry criteria, and the maturity level it represents within the product data governance framework.',
    `state_name` STRING COMMENT 'Human-readable name of the lifecycle state as displayed in the Teamcenter PLM user interface and engineering reports (e.g., Concept, Under Review, Released for Production, Obsolete).',
    `status` STRING COMMENT 'Operational status of this lifecycle state configuration record. Active states are available for assignment to PLM objects; Inactive states are suspended; Deprecated states are retained for historical reference only.. Valid values are `active|inactive|deprecated`',
    `teamcenter_policy_name` STRING COMMENT 'Name of the Teamcenter PLM lifecycle policy (policy object) under which this state is defined. A lifecycle policy groups related states and transition rules for a specific object type family.',
    `teamcenter_state_uid` STRING COMMENT 'Native Siemens Teamcenter PLM system unique identifier (UID) for this lifecycle state object. Used for cross-system traceability and integration with Teamcenter APIs and downstream PLM-ERP interfaces.',
    CONSTRAINT pk_plm_lifecycle_state PRIMARY KEY(`plm_lifecycle_state_id`)
) COMMENT 'Reference record defining the authorized lifecycle states and state transition rules for PLM-managed objects (components, BOMs, drawings, CAD models) within the Teamcenter PLM workflow. Captures state code, state name, allowed transitions, required approvals, and applicable object types. Provides the governance framework for product data maturity progression from concept through obsolescence.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`substitute_component` (
    `substitute_component_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for the substitute component association record in the Databricks Silver Layer.',
    `bom_line_id` BIGINT COMMENT 'Foreign key linking to engineering.bom_line. Business justification: A substitute component is defined as an approved alternate for a specific primary component in the BOM. Linking substitute_component to bom_line identifies the exact BOM line item (primary component p',
    `ecn_id` BIGINT COMMENT 'Foreign key linking to engineering.ecn. Business justification: substitute_component.ecn_number is a STRING reference to the ECN that authorized this substitution. Replacing with FK ecn_id → ecn.ecn_id enforces change management traceability for approved substitut',
    `engineering_bom_id` BIGINT COMMENT 'Foreign key linking to engineering.bom. Business justification: substitute_component.applicable_bom_number is a STRING reference to the BOM where this substitution is applicable. Replacing with FK bom_id → bom.bom_id establishes the authoritative substitution-to-B',
    `material_specification_id` BIGINT COMMENT 'Foreign key linking to engineering.material_specification. Business justification: Substitute components must meet the same or equivalent material specifications as the primary component they replace. Linking substitute_component to material_specification provides traceability from ',
    `substitution_id` BIGINT COMMENT 'Foreign key linking to product.substitution. Business justification: Engineering-approved substitute components must align with commercial substitution rules managed in the product domain. Procurement and production use this link to validate that engineering substitute',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to procurement.supplier. Business justification: Substitute components are typically sourced from alternative suppliers. Engineerings substitute component record must reference the procurement supplier master so buyers can immediately source the su',
    `approved_by` STRING COMMENT 'Name or employee identifier of the authorized engineer or manager who approved this substitute component association for use in production.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the substitute component association was formally approved, providing an audit trail for quality management and regulatory compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `bom_usage` STRING COMMENT 'Specifies the BOM usage context in which this substitution is applicable, aligning with SAP BOM usage categories (e.g., production BOM, engineering BOM, costing BOM).. Valid values are `production|engineering|costing|plant_maintenance|universal`',
    `cost_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the standard cost delta value, supporting multi-currency operations across global manufacturing sites.. Valid values are `^[A-Z]{3}$`',
    `cost_impact_indicator` STRING COMMENT 'Indicates the directional cost impact of using the substitute component compared to the primary component, supporting cost management and COGS analysis without storing calculated values.. Valid values are `cost_increase|cost_decrease|cost_neutral|unknown`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this substitute component association record was first created in the system, providing a full audit trail for data governance and compliance purposes.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `export_control_flag` BOOLEAN COMMENT 'Indicates whether the substitute component is subject to export control regulations (e.g., EAR, ITAR), which may restrict its use in certain geographies or customer applications and require additional compliance review.. Valid values are `true|false`',
    `form_fit_function_flag` BOOLEAN COMMENT 'Indicates whether the substitute component is a true form, fit, and function equivalent to the primary component, meaning it can be used without any design or process modification. Critical for engineering change and quality management decisions.. Valid values are `true|false`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when this substitute component association record was most recently updated, supporting change tracking, delta processing, and audit compliance.. Valid values are `^d{4}-d{2}-d{2}Td{2}:d{2}:d{2}.d{3}(Z|[+-]d{2}:d{2})$`',
    `lead_time_delta_days` STRING COMMENT 'The difference in procurement or manufacturing lead time in days between the substitute component and the primary component (substitute lead time minus primary lead time). Negative values indicate faster availability. Used in MRP scheduling and supply chain resilience planning.',
    `mrp_relevance_flag` BOOLEAN COMMENT 'Indicates whether this substitute component record is active and visible to the MRP engine for automatic exception handling and alternate material selection during planning runs.. Valid values are `true|false`',
    `originating_department` STRING COMMENT 'The business department that originated the substitute component request, used for workflow routing, accountability tracking, and cross-functional reporting.. Valid values are `engineering|procurement|supply_chain|quality|production_planning|manufacturing`',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility or site where this substitute component association is valid. Substitutions may be plant-specific due to local supplier availability or process constraints.. Valid values are `^[A-Z0-9]{4}$`',
    `priority_rank` STRING COMMENT 'Numeric rank indicating the preference order when multiple substitutes exist for the same primary component. Lower values indicate higher preference (1 = most preferred). Used by MRP to sequence substitute selection.. Valid values are `^[1-9][0-9]*$`',
    `quantity_conversion_factor` DECIMAL(18,2) COMMENT 'Multiplier applied to the original BOM quantity when using the substitute component. A value of 1.0 means the substitute is used in the same quantity; values other than 1.0 indicate a quantity adjustment is required (e.g., 2.0 means twice as many substitutes are needed).',
    `record_number` STRING COMMENT 'Business-facing unique identifier for the substitute component association record, used for cross-system referencing and audit trails.. Valid values are `^SUB-[A-Z0-9]{3,20}$`',
    `regulatory_compliance_impact` STRING COMMENT 'Indicates whether using this substitute component triggers a regulatory compliance review, such as RoHS, REACH, CE Marking, or UL certification re-assessment. Ensures regulatory obligations are not inadvertently violated during substitution.. Valid values are `no_impact|rohs_review_required|reach_review_required|ce_marking_review_required|ul_review_required|multiple_reviews_required`',
    `requested_by` STRING COMMENT 'Name or employee identifier of the person who initiated the request to establish this substitute component association, typically a supply chain planner, procurement specialist, or design engineer.',
    `requires_engineering_approval` BOOLEAN COMMENT 'Indicates whether use of this substitute component requires explicit engineering sign-off prior to production use, beyond the standard approval captured in the status field.. Valid values are `true|false`',
    `requires_quality_revalidation` BOOLEAN COMMENT 'Indicates whether use of this substitute component triggers a quality revalidation activity such as First Article Inspection (FAI), updated control plan, or re-qualification testing before production release.. Valid values are `true|false`',
    `restriction_notes` STRING COMMENT 'Detailed notes describing any restrictions, limitations, or special handling instructions associated with using this substitute component, including regulatory, safety, or performance constraints.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this substitute component association record was sourced, supporting data lineage and reconciliation in the Databricks Silver Layer.. Valid values are `SAP_S4HANA|TEAMCENTER|OPCENTER|MANUAL|ARIBA`',
    `source_system_key` STRING COMMENT 'The natural or surrogate key of this record in the originating source system (e.g., SAP substitute material record key), enabling reverse lookup and delta processing in the Silver Layer ingestion pipeline.',
    `standard_cost_delta` DECIMAL(18,2) COMMENT 'The difference in standard cost per unit between the substitute component and the primary component (substitute cost minus primary cost). Negative values indicate cost savings. Used for financial impact assessment and BOM costing.',
    `status` STRING COMMENT 'Current lifecycle and approval status of the substitute component record, governing whether it may be used in production planning and Material Requirements Planning (MRP) runs.. Valid values are `draft|pending_approval|approved|rejected|superseded|expired|withdrawn`',
    `substitution_reason_code` STRING COMMENT 'Standardized reason code explaining why this substitute component was identified and approved. Supports root cause analysis, supply chain resilience reporting, and procurement strategy decisions.. Valid values are `obsolescence|supply_shortage|cost_reduction|quality_improvement|regulatory_compliance|lead_time_reduction|supplier_change|engineering_change|emergency_procurement`',
    `substitution_type` STRING COMMENT 'Classification of the substitution relationship: full indicates the substitute is interchangeable in all contexts; conditional requires specific conditions to be met; temporary is time-bounded; emergency is approved only for urgent supply disruptions.. Valid values are `full|conditional|temporary|emergency`',
    `teamcenter_item_code` STRING COMMENT 'Reference identifier for this substitute component association record in Siemens Teamcenter PLM, enabling cross-system traceability between the Databricks Silver Layer and the PLM system of record.',
    `unit_of_measure` STRING COMMENT 'Unit of measure applicable to the substitute component quantity, which may differ from the primary components unit of measure when a conversion is required.. Valid values are `EA|KG|M|M2|M3|L|PC|SET|BOX|ROLL|MTR`',
    `use_condition` STRING COMMENT 'Free-text or structured description of the specific conditions under which this substitute may be used, such as only when primary component stock is zero, applicable for customer orders above 100 units, or valid only for non-safety-critical assemblies.',
    `valid_from_date` DATE COMMENT 'The date from which this substitute component association becomes effective and may be used in production planning and BOM resolution.. Valid values are `^d{4}-d{2}-d{2}$`',
    `valid_to_date` DATE COMMENT 'The date after which this substitute component association expires and is no longer valid for use. Null indicates no expiry. Used to manage temporary substitutions and time-bounded approvals.. Valid values are `^d{4}-d{2}-d{2}$`',
    CONSTRAINT pk_substitute_component PRIMARY KEY(`substitute_component_id`)
) COMMENT 'Association record defining approved substitute or alternate components that can replace a primary component in a BOM when the primary is unavailable or obsolete. Captures the primary component reference, substitute component reference, substitution type (full, conditional, temporary), applicable BOM context, approval status, and any use restrictions or quantity adjustments. Supports MRP exception handling and supply chain resilience.';

CREATE OR REPLACE TABLE `manufacturing_ecm`.`engineering`.`component_tooling_assignment` (
    `component_tooling_assignment_id` BIGINT COMMENT 'Primary key for the component_tooling_assignment association',
    `bom_line_id` BIGINT COMMENT 'Foreign key linking to the BOM line item (component) that requires this tooling assignment.',
    `tooling_equipment_id` BIGINT COMMENT 'Foreign key linking to the tooling or equipment master record assigned to this component.',
    `effective_from_date` DATE COMMENT 'The date from which this component-tooling assignment is valid for production use. Aligns with engineering change effectivity and PPAP approval windows. Belongs to the assignment, not to the BOM line or tool master independently.',
    `effective_to_date` DATE COMMENT 'The date after which this component-tooling assignment is no longer valid. Used to manage tool retirement, design changes, and supersession. Belongs to the assignment relationship.',
    `plant_code` STRING COMMENT 'SAP plant code identifying the manufacturing facility where this specific component-tooling assignment applies. The same component may require different tools at different plants. Belongs to the assignment because it scopes the pairing to a specific production site.',
    `setup_sequence` STRING COMMENT 'Numeric order in which this tool must be set up relative to other tools required for the same BOM component. Belongs to the assignment because sequence is specific to the component-tool pairing, not to the tool or component alone.',
    `usage_type` STRING COMMENT 'Classifies the functional role of the tool in manufacturing this component (e.g., FIXTURE for holding, CUTTING_TOOL for machining, GAUGE for inspection). Belongs to the assignment because the same tool may serve different roles for different components.',
    CONSTRAINT pk_component_tooling_assignment PRIMARY KEY(`component_tooling_assignment_id`)
) COMMENT 'This association product represents the Assignment relationship between a BOM line item (component) and a tooling/equipment master record. It captures which specific tools are required to manufacture a given component, including the role of each tool, its setup sequence, effectivity window, and the plant where the assignment applies. Each record links one bom_line to one tooling_equipment with attributes that exist only in the context of this component-tool pairing. Supports PPAP qualification, tooling planning, and MRP tooling requirement explosion.. Existence Justification: In industrial manufacturing, a BOM line item (component) genuinely requires multiple specialized tools simultaneously — e.g., a machined part needs a fixture, a cutting tool, and a gauge — while each tool is shared across many different BOM components across different assemblies and plants. This is an operationally managed relationship: engineering teams actively create, update, and retire component-tooling assignments as part of PPAP qualification, tooling planning, and production readiness. The relationship carries its own data (usage type, setup sequence, effectivity dates, plant scope) that belongs to neither the BOM line nor the tool master alone.';

